const stopE = flow.get("stopE") || false;
if (stopE || msg.topic === "emergencia") {
    let timer = context.get("timer");
    if (timer) { clearInterval(timer); context.set("timer", null); }
    context.set("valorActual", 0);
    flow.set("objetivo", 0);
    flow.set("start", false);
    node.send({ payload: 0 });
    return null;
}

const PASO = 1;
const INTERVALO_MS = 100;

const encStart = flow.get("start") || false;
const encJog   = flow.get("jog")   || false;
const activo   = encStart || encJog;

// Guardar valor del slider SIEMPRE (para recordarlo)
// pero NO arrancar si el sistema está inactivo
if (msg.payload !== undefined && typeof msg.payload === "number") {
    if (msg.topic !== "salida") {
        flow.set("sliderValor", msg.payload);
    }
    if (activo) {
        flow.set("objetivo", msg.payload);
    }
}

const objetivo = flow.get("objetivo") || 0;
let actual = context.get("valorActual") || 0;
let timer = context.get("timer");
if (timer) clearInterval(timer);

// Si no está activo y ya está en 0, no hacer nada
if (!activo && actual === 0 && objetivo === 0) {
    node.send({ payload: 0 });
    return null;
}


// Arrancar rampa solo si está activo o si tiene que bajar
timer = setInterval(function() {
    actual = context.get("valorActual") || 0;
    const obj = flow.get("objetivo") || 0;
    const enc = flow.get("start") || flow.get("jog") || false;
    const destino = enc ? obj : 0;

    if (actual < destino) {
        actual = Math.min(actual + PASO, destino);
    } else if (actual > destino) {
        actual = Math.max(actual - PASO, destino);
    }

    context.set("valorActual", actual);
    flow.set("valorActual", actual);   
    node.send({ payload: actual });

    if (actual === destino) {
        clearInterval(context.get("timer"));
        context.set("timer", null);
        flow.set("valorActual", 0);
        flow.set("objetivo", 0);
        flow.set("rampa", false);
    }
}, INTERVALO_MS);

context.set("timer", timer);
//msg.payload = "ok";
//return msg;
return null;

// === ENCLAVAMIENTO DE MARCHA ===

const topic = msg.topic;
const valor = msg.payload;

// --- PARADA DE EMERGENCIA: corta todo sin rampa ---
const stopE = flow.get("stopE") || false;
if (stopE) {
    flow.set("rampa", false);
    flow.set("start", false);
    flow.set("jog",   false);
    flow.set("objetivo", 0);       
    node.send({ payload: 0, topic: "emergencia" });
    return null;
}

// --- ENABLE: si se apaga, parar con rampa ---
const enable = flow.get("enable") || false;
if (!enable) {
    flow.set("start", false);
    flow.set("jog", false);
    flow.set("rampa", false);
    return { payload: 0, topic: "salida" };
}

// Leer estados actuales
let encStart = flow.get("start") || false;
let encJog   = flow.get("jog")   || false;
let si_verde   = flow.get("verde")   || false;

// --- STOP: corta todo ---
if (topic === "stop" && si_verde) {      //
    flow.set("rampa", true);
    flow.set("start", false);
    flow.set("jog",   false);
    node.send([{ payload: false, topic: "salida" }, { payload: true }]);
    return null;
}

// --- START: enclavamiento ---
if (topic === "start") {
    if (valor === true && !encJog) {
        flow.set("start", true);
        const sliderVal = flow.get("sliderValor") || 0;
        flow.set("objetivo", sliderVal);
        return { payload: sliderVal, topic: "salida" };
    }
}

// --- JOG: sin enclavamiento, solo mientras se mantiene ---
if (topic === "jog") {
    if (!encStart) {
        flow.set("jog", valor);

        if (valor === true) {
            const jogX2 = flow.get("jogX2") || false;
            const tope  = jogX2 ? 20 : 10;
            flow.set("objetivo", tope);
        } else {
            const sliderVal = flow.get("sliderValor") || 0;
            flow.set("objetivo", sliderVal);
        }
    }
}

// Leer valores actualizados
encStart = flow.get("start");
encJog   = flow.get("jog");

const obj = flow.get("objetivo") || 0;
return { payload: obj, topic: "salida" };

